import{c as m,a7 as r,y as l,B as i,v as t,D as a}from"./chunks/framework.3cjvm90C.js";const s=JSON.parse('{"title":"QTRAN 值分解算法","description":"介绍 QTRAN 如何放松单调性假设实现更一般的值函数分解","frontmatter":{"title":"QTRAN 值分解算法","description":"介绍 QTRAN 如何放松单调性假设实现更一般的值函数分解"},"headers":[],"relativePath":"rlwiki/papers/qtran.md","filePath":"rlwiki/papers/qtran.md","lastUpdated":1782448598000}'),h={name:"rlwiki/papers/qtran.md"};function o(_,e,p,$,n,u){return r(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="qtran" tabindex="-1">QTRAN <a class="header-anchor" href="#qtran" aria-label="Permalink to “QTRAN”">​</a></h1><p>论文链接：<a href="https://arxiv.org/abs/1905.05408" target="_blank" rel="noreferrer">QTRAN: Learning to Factorize with Transformation for Cooperative Multi-Agent Reinforcement Learning, ICML 2019</a></p><p>代码： <a href="https://github.com/Sonkyunghwan/QTRAN" target="_blank" rel="noreferrer">https://github.com/Sonkyunghwan/QTRAN</a></p><p>VDN 和 QMIX 都是值分解领域的两大标杆性文章， VDN 将联合动作价值函数分解为单个动作价值函数的和。QMIX 扩展了这种可加性的值函数，进行因子分解，将联合作用价值函数表示为单调函数，而不是仅仅为加和，从而实现了环境的更进一步扩展。</p><p>值分解其实就是在保证联合动作取 argmax 的时候能够是对各个智能体的值函数取 argmax。VDN 中采用的是线性求和的方式， QMIX 中采用的是保证单调性。对于一些任务，比如像联合动作的最优就是各个智能体的单独的最优的值函数，这样的问题可以采用这种方式，对于不是这类型的问题的话，这种限制就太强了。</p><p>QTRAN 提出了一种新的值分解的算法，将原来的联合行动价值函数转换为一种易于分解的函数，它们具有相同的最优行动，这种方法有更一般的降解，适合更多的场合，号称可以降解一切可以降解任务。</p><h2 id="qtran-直观理解" tabindex="-1">QTRAN 直观理解 <a class="header-anchor" href="#qtran-直观理解" aria-label="Permalink to “QTRAN 直观理解”">​</a></h2><p>在 VDN 和 QMIX 中是将 $$ Q_{\\mathrm{jt} }$$通过累加求和和保证单调性的方式来分解的，作者这里提出一种更加鲁棒的分解方式，将原始的 $$Q_{\\mathrm{jt} }$$ 映射成 $Q_{\\mathrm{jt} }^{\\prime}$ ，通过 $Q_{\\mathrm{jt} }^{\\prime}$去分解值函数到各个子智能体上，来保证学到的$$Q_{\\mathrm{jt} }^{\\prime}$$与真实的动作值函数 $Q^{*}$ 非常接近。这样在学习真实的动作值函数的时候，没有像 VDN 和 QMIX 那样对其加上一些累加求和和保证单调性的限制，所以它能学地更好。</p><p>但是由于部分可观测地限制，这个 $Q_{\\mathrm{jt} }^{\\prime}$ 是没有办法用来进行具体地决策的，所以我们需要去找到$Q_{\\mathrm{jt} }$、$Q_{\\mathrm{jt} }^{\\prime}$</p><p>和$\\left[Q_{i}\\right]$三者之间的关系。</p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><h3 id="decentralized-pomdp" tabindex="-1">Decentralized POMDP <a class="header-anchor" href="#decentralized-pomdp" aria-label="Permalink to “Decentralized POMDP”">​</a></h3><p>Decentralized POMDP 是用来给合作式多智能体任务建模的标准方法，简称 DEC-POMDP，表示为$\\mathcal{G}=&lt;\\mathcal{S}, \\mathcal{U}, P, r, \\mathcal{Z}, O, N, \\gamma&gt;$：</p><ul><li>$i \\in N:={1,…,N}$： N 个 agents.</li><li>$s \\in S$：环境的真实状态</li><li>$u_{i} \\in U$：每个 agent 的动作</li><li>$u:=\\left[u_{i}\\right]_{i=1}^{N} \\in \\mathcal{U}^{N}$：联合动作向量</li><li>$P\\left(s^{\\prime} | s, u\\right): \\mathcal{S} \\times \\mathcal{U}^{N} \\times \\mathcal{S} \\mapsto[0,1]$：状态转移方程</li><li>$r(s, u): \\mathcal{S} \\times \\mathcal{U}^{N} \\mapsto \\mathbb{R}$：共享的联合奖励函数</li><li>$\\gamma \\in[0,1)$：折扣因子</li><li>$z = O(s, i): \\mathcal{S} \\times \\mathcal{N} \\mapsto \\mathcal{Z}$：每个 agent 自己的部分观察</li><li>$\\tau_{i} \\in \\mathcal{T}:=(\\mathcal{Z} \\times \\mathcal{U})^{*}$：每个 agent 的动作-观察历史</li></ul><h3 id="igm-condition-and-factorizable-task" tabindex="-1">IGM Condition and Factorizable Task <a class="header-anchor" href="#igm-condition-and-factorizable-task" aria-label="Permalink to “IGM Condition and Factorizable Task”">​</a></h3><p>下面给出 IGM 与可分解任务的定义。IGM 全称 Individual-Global-Max，可以理解为独立值函数最大化与联合值函数最大化的一致性，具体定义为；</p><p>给定一个联合动作值函数$Q_{\\mathrm{jt} }: \\mathcal{T}^{N} \\times \\mathcal{U}^{N} \\mapsto \\mathbb{R}$，其中$\\tau \\in \\mathcal{T}^{N}$是联合动作-观察历史，如果存在一系列的独立动作值函数$\\left[Q_{i}: \\mathcal{T} \\times \\mathcal{U} \\mapsto \\mathbb{R}\\right]_{i=1}^{N}$使得如下条件成立：</p>',17),t("p",null,[a("$$\\arg \\max "),t("em",null,"{\\boldsymbol{u} } Q"),a("{\\text {jt } }(\\boldsymbol{\\tau}, \\boldsymbol{u})=\\left(\\begin{array}{c} \\arg \\max "),t("em",{1:""},"{u"),a(" } Q_{1}\\left(\\tau_{1}, u_{1}\\right) \\ \\vdots \\ \\arg \\max "),t("em",{N:""},"{u"),a(" } Q_{N}\\left(\\tau_{n}, u_{N}\\right) \\end{array}\\right)$$")],-1),i('<p>则认为$\\left[Q_{i}\\right]$对于$Q_{\\mathrm{jt} }$满足 IGM，即$Q_{\\mathrm{jt} }(\\tau, \\boldsymbol{u})$可以被$\\left[Q_{i}\\left(\\tau_{i}, u_{i}\\right)\\right]$分解。</p><p>如果某任务的$Q_{\\mathrm{jt} }(\\tau, \\boldsymbol{u})$对于所有的$\\tau \\in \\mathcal{T}^{N}$都可分解，那么就认为该任务本身是可分解的。</p><p>VDN 和 QMIX 的分解方式其实本质上是满足 IGM 的充分非必要条件：</p><p>$$\\begin{aligned} &amp;\\text { (Additivity) } \\quad Q_{\\mathrm{jt} }(\\tau, u)=\\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, u_{i}\\right)\\ &amp;\\text { (Monotonicity) } \\frac{\\partial Q_{\\text {jt } }(\\tau, u)}{\\partial Q_{i}\\left(\\tau_{i}, u_{i}\\right)} \\geq 0, \\quad \\forall i \\in \\mathcal{N} \\end{aligned}$$</p><p>它们与本文 QTRAN 方法的关系可以用下图表示：</p><img src="https://s1.ax1x.com/2020/08/13/dSaM7Q.png" alt="dSaM7Q.png" style="zoom:50%;"><h3 id="qtran-1" tabindex="-1">QTRAN <a class="header-anchor" href="#qtran-1" aria-label="Permalink to “QTRAN”">​</a></h3><p>QTRAN 核心思想是将原有的联合行动价值函数$Q_{\\mathrm{jt} }(\\tau, u)$转换为与$Q_{\\mathrm{jt} }(\\tau, u)$共享最优联合行动的$Q^{&#39;}_{\\mathrm{jt} }(\\tau, u)$</p><h4 id="可分解值函数" tabindex="-1">可分解值函数 <a class="header-anchor" href="#可分解值函数" aria-label="Permalink to “可分解值函数”">​</a></h4><p>可分解值函数的特点由如下定理给出：</p><p><strong>Theorem 1</strong>：令$\\overline{\\boldsymbol{u} }_{i}=\\arg \\max_{u_{i} } Q_{i}\\left(\\tau_{i}, u_{i}\\right)$为最优的局部动作，$\\overline{\\boldsymbol{u} }=\\left[\\bar{u}_{i}\\right]_{i=1}^{N}$，当满足以下条件时，一个可分解的联合动作值函数$Q_{\\text {jt } }(\\tau, \\boldsymbol{u})$可分解为$\\left[Q_{i}\\left(\\tau_{i}, u_{i}\\right)\\right]$：</p><p>$$\\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, u_{i}\\right)-Q_{\\mathrm{jt} }(\\tau, u)+V_{\\mathrm{jt} }(\\tau)=\\left{\\begin{array}{ll} 0 &amp; u=\\bar{u}, \\ \\geq 0 &amp; u \\neq \\bar{u} \\end{array}\\right.$$</p><p>其中</p><p>$$V_{\\mathrm{jt} }(\\tau)=\\max <em>{u} Q</em>{\\mathrm{jt} }(\\tau, u)-\\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, \\bar{u}_{i}\\right)$$</p><p>证明如下：</p><p>$$\\begin{aligned} Q_{\\mathrm{jt} }(\\tau, \\bar{u}) &amp;=\\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, \\bar{u}<em>{i}\\right)+V</em>{\\mathrm{jt} }(\\tau) \\quad(\\text { From }(4 \\mathrm{a})) \\ &amp; \\geq \\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, u_{i}\\right)+V_{\\mathrm{jt} }(\\tau) \\ &amp; \\geq Q_{\\mathrm{jt} }(\\tau, u) \\quad(\\text { From }(4 \\mathrm{b})) \\end{aligned}$$</p><p>注意，对于映射变化$\\phi(\\boldsymbol{Q})=A \\cdot \\boldsymbol{Q}+B$来说，如果$A=\\left[a_{ii} \\right] \\in \\mathbb{R}_{+}^{N \\times N}$是对称的对角矩阵且$a_{i i}&gt;0, \\forall i$，$B=\\left[b_{i}\\right] \\in \\mathbb{R}^{N}$，那么上述定理依旧成立。可以把$A$与$B$看作是缩放与偏差。</p><p>因此可以找到一个转换联合动作值函数$Q^{&#39;}_{\\mathrm{jt} }(\\tau, u)$满足上述定理：</p><p>$$Q_{\\mathrm{jt} }^{\\prime}(\\tau, u):=\\sum_{i=1}^{N} Q_{i}\\left(\\tau_{i}, u_{i}\\right)$$</p><p>这是因为这种加和形式下，$\\left[Q_{i}\\right]$对于$Q_{\\mathrm{jt} }^{\\prime}$满足 IGM，又因为$\\arg \\max_{\\boldsymbol{u} } Q_{\\text {jt } }(\\boldsymbol{\\tau}, \\boldsymbol{u})=\\arg \\max_{\\boldsymbol{u} } Q_{\\text {jt } }^{\\prime}(\\boldsymbol{\\tau}, \\boldsymbol{u})$，所以$\\left[Q_{i}\\right]$就是$Q_{\\mathrm{jt} }^{\\prime}$的分解。</p><h4 id="方法框架" tabindex="-1">方法框架 <a class="header-anchor" href="#方法框架" aria-label="Permalink to “方法框架”">​</a></h4><p>QTRAN 的框架如下图所示：</p><img src="https://s1.ax1x.com/2020/08/13/dSae6f.png" alt="dSae6f.png" style="zoom:90%;"><p>其中包含三个网络：</p><p>$$\\begin{aligned} &amp;\\text{独立动作值函数网络：}f_{\\mathbf{q} }:\\left(\\tau_{i}, u_{i}\\right) \\mapsto Q_{i}\\ &amp;\\text{联合动作值函数网络：}f_{\\mathrm{r} }😦\\tau, \\boldsymbol{u}) \\mapsto Q_{\\mathrm{jt} }\\ &amp;\\text{状态值函数网络：}f_{\\mathbf{v} }: \\boldsymbol{\\tau} \\mapsto V_{j t} \\end{aligned}$$</p><p>其中，联合动作值函数网络使用所有独立动作值函数网络采样得到的动作进行更新，并连接各个所有独立动作值函数网络底层输出的隐性特征$h_{i}\\left(\\tau_{i}, u_{i}\\right)=\\left[h_{Q, i}\\left(\\tau_{i}, u_{i}\\right), h_{V, i}\\left(\\tau_{i}\\right)\\right]$</p><h4 id="损失函数" tabindex="-1">损失函数 <a class="header-anchor" href="#损失函数" aria-label="Permalink to “损失函数”">​</a></h4><p>QTRAN 中的 loss 函数由三部分组成：</p><p>$$L\\left(\\boldsymbol{\\tau}, \\boldsymbol{u}, \\boldsymbol{r}, \\boldsymbol{\\tau}^{\\prime} ; \\boldsymbol{\\theta}\\right)=L_{\\mathrm{td} }+\\lambda_{\\mathrm{opt} } L_{\\mathrm{opt} }+\\lambda_{\\mathrm{nopt} } L_{\\mathrm{nopt} }$$</p><p>其中：$L_{\\mathrm{td} }$用于评估真实的动作值，$ L_{\\mathrm{opt} }$和$L_{\\mathrm{nopt} }$用于评估分解$Q_{jt}$为$\\left[Q_{i}\\right]$时是否满足 Theorem 1。由于 Theorem 1 的条件需要在训练中采样大量样本才能满足，这里做了简化，即在训练$ L_{\\mathrm{opt} }$和$L_{\\mathrm{nopt} }$时固定$Q_{jt}$，并使用$\\hat{Q}_{\\mathrm{jt} }$来表示这个固定的$Q_{jt}$。具体每个损失函数的定义如下：</p><p>$$\\begin{aligned} L_{\\mathrm{td} }(; \\boldsymbol{\\theta}) &amp;=\\left(Q_{\\mathrm{jt} }(\\tau, \\boldsymbol{u})-y^{\\mathrm{d} \\mathrm{q} \\mathrm{n} }\\left(r, \\boldsymbol{\\tau}^{\\prime} ; \\boldsymbol{\\theta}^{-}\\right)\\right)^{2} \\ L_{\\mathrm{opt} }(; \\boldsymbol{\\theta}) &amp;=\\left(Q_{\\mathrm{jt} }^{\\prime}(\\tau, \\overline{\\boldsymbol{u} })-\\hat{Q}<em>{\\mathrm{jt} }(\\tau, \\overline{\\boldsymbol{u} })+V</em>{\\mathrm{jt} }(\\tau)\\right)^{2} \\ L_{\\mathrm{nopt} }(; \\boldsymbol{\\theta}) &amp;=\\left(\\min \\left[Q_{\\mathrm{jt} }^{\\prime}(\\tau, \\boldsymbol{u})-\\hat{Q}<em>{\\mathrm{jt} }(\\tau, \\boldsymbol{u})+V</em>{\\mathrm{jt} }(\\tau), 0\\right]\\right)^{2} \\end{aligned}$$</p><p>其中$y^{\\mathrm{dqn} }\\left(r, \\boldsymbol{\\tau}^{\\prime} ; \\boldsymbol{\\theta}^{-}\\right)=r+\\gamma Q_{\\mathrm{jt} }\\left(\\tau^{\\prime}, \\overline{\\boldsymbol{u} }^{\\prime} ; \\boldsymbol{\\theta}^{-}\\right)$，$\\bar{u}^{\\prime}=\\left[\\arg \\max_{u_{1} } Q_{i}\\left(\\tau_{i}^{\\prime}, u_{i} ; \\boldsymbol{\\theta}^{-}\\right)\\right]_{i-1}^{N}$，$\\theta^{-}$为 DQN 目标网络的参数。</p><h4 id="修改对联合行动价值函数的追踪" tabindex="-1">修改对联合行动价值函数的追踪 <a class="header-anchor" href="#修改对联合行动价值函数的追踪" aria-label="Permalink to “修改对联合行动价值函数的追踪”">​</a></h4><p>上述版本的 QTRAN 称为 QTRAN-base，反映其如何追踪联合行动价值函数的基本性质。然而， Theorem 1 的第二个条件太宽，导致神经网络无法完成构建$Q_{jt}$正确的分解，即对非最优行为施加不良影响，这进而影响了训练过程的稳定性和收敛速度。这促使去研究比 Theorem 1 的第二个条件更强的条件，同时满足 Theorem 1 的仿射变换的不变性：</p><p><strong>Theorem 2</strong>： Theorem 1 的第二个条件替换为如下条件时， Theorem 1 依旧成立。当$u=\\bar{u}$时，</p><p>$$\\begin{aligned} \\min_{u_{i} \\in \\mathcal{U} }[&amp; Q_{\\mathrm{jt} }^{\\prime}\\left(\\tau, u_{i}, \\boldsymbol{u}<em>{-i}\\right)-Q</em>{\\mathrm{jt} }\\left(\\tau, u_{i}, \\boldsymbol{u}<em>{-i}\\right) + \\left.V</em>{\\mathrm{jt} }(\\tau)\\right]=0, \\quad \\forall i=1, \\ldots, N \\end{aligned}$$</p><p>其中$\\boldsymbol{u}_{-i}=\\left(u_{1}, \\ldots, u_{i-1}, u_{i+1}, \\ldots, u_{N}\\right)$，即除了 agent $i$以外的所有动作。</p><p>为了实现 Theorem 2，使用反事实联合网络来替代联合动作值函数网络，即对于每个 agent 都设置一个反事实网络$Q_{\\mathrm{jt} }\\left(\\tau, \\cdot, \\boldsymbol{u}_{-i}\\right)$。同时将$L_{\\text {nopt } }$替换为$L_{\\text {nopt-min } }$：</p>',38),t("p",null,[a("$$L_{\\mathrm{nopt}-\\min }\\left(\\tau, u, r, \\tau^{\\prime} ; \\theta\\right)=\\frac{1}{N} \\sum_{i=1}^{N}\\left(\\min "),t("em",{i:""},"{u"),a(" \\in U} D\\left(\\tau, u_{i}, u_{-i}\\right)\\right)^{2}$$")],-1),i('<p>其中$D\\left(\\tau, u_{i}, u_{-i}\\right)=Q_{\\mathrm{jt} }^{\\prime}\\left(\\tau, u_{i}, u_{-i}\\right)-\\hat{Q}_{\\mathrm{jt} }\\left(\\tau, u_{i}, u_{-i}\\right)+V_{\\mathrm{jt} }(\\tau)$</p><h2 id="实验内容" tabindex="-1">实验内容 <a class="header-anchor" href="#实验内容" aria-label="Permalink to “实验内容”">​</a></h2><p>在下图的单状态马尔科夫博弈中， QTRAN 是唯一获得最优解的：</p><img src="https://s1.ax1x.com/2020/08/13/dSaunS.png" alt="dSaunS.png" style="zoom:67%;"><p>QTRAN-alt 比 QTRAN-base 更好地区分最优动作与非最优动作：</p><img src="https://s1.ax1x.com/2020/08/13/dSaK0g.png" alt="dSaK0g.png" style="zoom:80%;"><p>将 Multi-domain Gaussian Squeeze、Modified predator-prey 等环境设置为强迫合作式的环境，表现超越了 VDN 与 QMIX：</p><img src="https://s1.ax1x.com/2020/08/13/dSamX8.png" alt="dSamX8.png" style="zoom:80%;"><h2 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h2><ul><li><p>分解的 Q 值依旧没有实际含义</p></li><li><p>在复杂的 MARL 任务上的实际表现很差，因为由于 QTRAN 使用的约束太过松散，实现时的过多近似会导致在很多任务上效果不如 Q-mix 理想</p></li></ul><h2 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h2><ul><li>进一步扩大了 Q 值分解理论的适用范围</li><li>采用类似 dueling network 的结构可以提升学习效果, 加速收敛</li></ul>',12)])])}const b=m(h,[["render",o]]);export{s as __pageData,b as default};
